module sub_64bit (
    input [63:0] A,
    input [63:0] B,
    output reg [63:0] result,
    output reg overflow
);

    assign result = A - B;

    assign overflow = ((A[63] == 0 && B[63] == 1 && result[63] == 1) || (A[63] == 1 && B[63] == 0 && result[63] == 0)) ? 1'b1 : 1'b0;
endmodule

module comparator_3bit (
    input [2:0] A,
    input [2:0] B,
    output A_greater,
    output A_equal,
    output A_less
);

assign A_greater = (A > B) ? 1'b1 : 1'b0;
assign A_equal = (A == B) ? 1'b1 : 1'b0;
assign A_less = (A < B) ? 1'b1 : 1'b0;
endmodule

module fixed_point_adder #(
    parameter Q = 15,
    parameter N = 32
) (
    input [N-1:0] a,
    input [N-1:0] b,
    output [N-1:0] c
);

reg [N-1:0] res;

assign c = res;

always @* begin

    if ((a[N-1] == b[N-1])) begin

        res = a + b;

        res[N-1] = a[N-1];
    end else begin

        if ($unsigned(a) > $unsigned(b)) begin

            res = a - b;

            res[N-1] = 0;
        end else begin

            res = b - a;

            res[N-1] = (res == 0 || res[N-1]) ? 1 : 0;
        end
    end
end
endmodule

module multi_16bit (
    input clk,
    input rst_n,
    input start,
    input [15:0] ain,
    input [15:0] bin,
    output [31:0] yout,
    output done
);

reg [15:0] areg, breg;
reg [31:0] yout_r;
reg [4:0] i;
reg done_r;
assign yout = yout_r;
assign done = done_r;
always@(posedge clk or negedge rst_n) begin
	if(!rst_n) begin
		i <= 0;
	end
	else if(start && i < 17) begin
		i <= i + 1;
	end
	else begin
		i <= 0;
	end
end
always@(posedge clk or negedge rst_n) begin
	if(!rst_n) begin
		done_r <= 0;
	end
	else if(i == 16) begin
		done_r <= 1;
	end
	else if(i == 17) begin
		done_r <= 0;
	end
end
always@(posedge clk or negedge rst_n) begin
	if(!rst_n) begin
		yout_r <= 0;
		areg <= 0;
		breg <= 0;
	end
	else if(start) begin
		case(i)
			0: begin
				areg <= ain;
				breg <= bin;
			end
			default: begin
				if(areg[i-1]) begin
					yout_r <= yout_r + (breg << (i-1));
				end
			end
		endcase
	end
end
endmodule

module multi_booth_8bit (
    output reg [15:0] p,
    output reg rdy,
    input clk,
    input reset,
    input [7:0] a,
    input [7:0] b
);

	reg [15:0] multiplier, multiplicand;
	reg [4:0] ctr;

	always@(posedge clk, posedge (reset)) begin
		if(reset) begin
			multiplicand <= {{8{a[7]}}, a};
			multiplier <= {{8{b[7]}}, b};
			p <= 0;
			rdy <= 0;
			ctr <= 0;
		end

		else begin
			if(ctr < 16) begin
				multiplicand <= multiplicand << 1;
				if(multiplier[ctr])
					p <= p + multiplicand;
				ctr <= ctr + 1;
			end

				rdy <= 1;
		end
	end

endmodule

module div_16bit (
    input wire [15:0] A,
    input wire [7:0] B,
    output reg [15:0] result,
    output reg [15:0] odd
);
    always @(*) begin
        if (B == 0) begin
            result = 0;
            odd = A;
        end else begin
            result = A / B;
            odd = A % B;
        end
    end
endmodule

module fixed_point_substractor #(
    parameter Q = 15,
    parameter N = 32
) (
    input [N-1:0] a,
    input [N-1:0] b,
    output reg [N-1:0] c
);

reg [N-1:0] res;

always @* begin

    res = 0;

    if (a[N-1] != b[N-1]) begin

        if (a[N-1] > b[N-1]) begin

            res = a + (~b + 1); 
            res[N-1] = 1; 
        end else begin

            res = ~a + 1 + b; 
            res[N-1] = 0; 
        end
    end else begin

        res = a - b;

        if (res == 0) begin
            res[N-1] = 0; 
        end
    end
end

assign c = res;
endmodule

module fixed_point_subtractor #(
	parameter Q = 15,
	parameter N = 32
	)
	(
    input [N-1:0] a,
    input [N-1:0] b,
    output [N-1:0] c
    );

reg [N-1:0] res;

assign c = res;

always @(a,b) begin

	if(a[N-1] == b[N-1]) begin					
		res[N-2:0] = a[N-2:0] - b[N-2:0];		
		res[N-1] = a[N-1];							


		end												

	else if(a[N-1] == 0 && b[N-1] == 1) begin		
		if( a[N-2:0] > b[N-2:0] ) begin					
			res[N-2:0] = a[N-2:0] + b[N-2:0];			
			res[N-1] = 0;										
			end
		else begin												
			res[N-2:0] = b[N-2:0] + a[N-2:0];		
			if (res[N-2:0] == 0)
				res[N-1] = 0;									
			else
				res[N-1] = 1;									
			end
		end
	else begin												
		if( a[N-2:0] > b[N-2:0] ) begin					
			res[N-2:0] = a[N-2:0] + b[N-2:0];			
			if (res[N-2:0] == 0)
				res[N-1] = 0;										
			else
				res[N-1] = 1;										
			end
		else begin												
			res[N-2:0] = b[N-2:0] + a[N-2:0];			
			res[N-1] = 0;										
			end
		end
	end
endmodule

module multi_8bit (
    input [7:0] A,
    input [7:0] B,
    output reg [15:0] product
);

integer i;
reg [15:0] temp_product;
reg [7:0] shifted_A;

always @* begin
    temp_product = 16'b0; 
    shifted_A = A; 

    for (i = 0; i < 8; i = i + 1) begin

        if (B[i]) begin

            temp_product = temp_product + (shifted_A << i);
        end
    end
end

assign product = temp_product;
endmodule

module freq_div (
    input CLK_in,
    output reg CLK_50,
    output reg CLK_10,
    output reg CLK_1,
    input RST
);

	reg CLK_50_reg, CLK_10_reg, CLK_1_reg;
	reg [3:0] cnt_10;
	reg [6:0] cnt_100;

	always@(posedge CLK_in or posedge RST) begin
		if(RST) begin
			CLK_50_reg <= 1'b0;
		end
		else begin
			CLK_50_reg <= ~CLK_50_reg;
		end
	end

	always@(posedge CLK_in or posedge RST) begin
		if(RST) begin
			cnt_10 <= 4'd0;
			CLK_10_reg <= 1'b0;
		end
		else begin
			if(cnt_10 == 4'd4) begin
				CLK_10_reg <= ~CLK_10_reg;
				cnt_10 <= 4'd0;
			end
			else begin
				cnt_10 <= cnt_10 + 1;
			end
		end
	end

	always@(posedge CLK_in or posedge RST) begin
		if(RST) begin
			cnt_100 <= 7'd0;
			CLK_1_reg <= 1'b0;
		end
		else begin
			if(cnt_100 == 7'd49) begin
				CLK_1_reg <= ~CLK_1_reg;
				cnt_100 <= 7'd0;
			end
			else begin
				cnt_100 <= cnt_100 + 1;
			end
		end
	end

	assign CLK_50 = CLK_50_reg;
	assign CLK_10 = CLK_10_reg;
	assign CLK_1 = CLK_1_reg;

endmodule

module freq_divbyfrac #(
    parameter MUL2_DIV_CLK = 7
) (
    input               rst_n,
    input               clk,
    output              clk_div
);

reg [1:0] count;
reg div_clk;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        count <= 0;
        div_clk <= 0;
    end else begin
        count <= count + 1;
        if (count == MUL2_DIV_CLK - 1) begin
            div_clk <= ~div_clk;
            count <= 0;
        end
    end
end

assign clk_div = div_clk;

endmodule

module edge_detect (
    input clk,
    input rst_n,
    input a,
    output reg rise,
    output reg down
);

reg prev_a;

always @(posedge clk or negedge rst_n) begin
    if (~rst_n) begin

        prev_a <= 1'b0;
        rise <= 1'b0;
        down <= 1'b0;
    end else begin

        prev_a <= a;

        if ((prev_a == 1'b0) && (a == 1'b1)) begin
            rise <= 1'b1;
        end else begin
            rise <= 1'b0;
        end

        if ((prev_a == 1'b1) && (a == 1'b0)) begin
            down <= 1'b1;
        end else begin
            down <= 1'b0;
        end
    end
end
endmodule

module fsm #(
    parameter s0 = 3'b000,
    parameter s1 = 3'b001,
    parameter s2 = 3'b010,
    parameter s3 = 3'b011,
    parameter s4 = 3'b100,
    parameter s5 = 3'b101
) (
    input IN,
    output reg MATCH,
    input CLK,
    input RST
);


reg [2:0] ST_cr, ST_nt;

always @(posedge CLK or posedge RST) begin
    if (RST) ST_cr <= s0; else ST_cr <= ST_nt;
end

always @(*) begin
    case(ST_cr)
        s0: begin
            if(IN==1'b1) ST_nt = s1; else ST_nt = s0;
        end

        s1: begin
            if(IN==1'b1) ST_nt = s1; else ST_nt = s2;
        end

        s2: begin
            if(IN==1'b1) ST_nt = s1; else ST_nt = s3;
        end

        s3: begin
            if(IN==1'b1) ST_nt = s4; else ST_nt = s0;
        end

        s4: begin
            if(IN==1'b1) ST_nt = s5; else ST_nt = s2;
        end

        s5: begin
            if(IN==1'b1) ST_nt = s1; else ST_nt = s2;
        end

        default: ST_nt = s0;
    endcase
end

assign MATCH = (RST) ? 1'b0 :
               ((ST_cr == s4) && (IN == 1'b1)) ? 1'b1 : 1'b0;
endmodule

module instr_reg (
    input clk,
    input rst,
    input [1:0] fetch,
    input [7:0] data,
    output [2:0] ins,
    output [4:0] ad1,
    output [7:0] ad2
);

reg [7:0] ins_p1, ins_p2;
assign ins = ins_p1[7:5];
assign ad1 = ins_p1[4:0];
assign ad2 = ins_p2;
always@(posedge clk or negedge rst) begin
    if(!rst) begin
        ins_p1 <= 8'b0;
        ins_p2 <= 8'b0;
    end
    else begin
        case(fetch)
            2'b01: ins_p1 <= data;
            2'b10: ins_p2 <= data;
            default: begin
                ins_p1 <= ins_p1;
                ins_p2 <= ins_p2;
            end
        endcase
    end
end
endmodule

module up_down_counter (
    input wire clk,
    input wire reset,
    input wire up_down,
    output reg [15:0] count
);
    always @(posedge clk or posedge (reset)) begin
        if(reset)
            count <= 16'b0;
        else if(up_down) count <= count + 1; else count <= count - 1;
    end
endmodule

