module add1 (
    input wire a,
    input wire b,
    input wire Cin,
    output wire y,
    output wire Co
);
    assign y = ((~a) & (~b) & Cin | (~a) & b & (~Cin) | a & (~b) & (~Cin) | (a & b & Cin));
    assign Co = ((~a & b & Cin) | (a & ~b & Cin) | (a & b & ~Cin) | (a & b & Cin));

endmodule

module multi_pipe_8bit #(
    parameter size = 8
) (
    input clk,
    input rst_n,
    input [size-1:0] mul_a,
    input [size-1:0] mul_b,
    input mul_en_in,
    output reg mul_en_out,
    output reg [size*2-1:0] mul_out
);

reg [2:0] mul_en_out_reg;
reg [7:0] mul_a_reg, mul_b_reg;
reg [15:0] mul_out_reg;
reg [15:0] temp[7:0];
reg [15:0] sum[3:0];
integer i;
always@(posedge clk or negedge rst_n)begin
    if(!rst_n)begin
        mul_en_out_reg <= 0;
        mul_en_out <= 0;
    end
    else begin
        mul_en_out_reg <= {mul_en_out_reg[1:0],mul_en_in};
        mul_en_out <= mul_en_out_reg[2];
    end
end
always@(posedge clk)begin
    if(mul_en_in)begin
        mul_a_reg <= mul_a;
        mul_b_reg <= mul_b;
    end
    else begin
        mul_a_reg <= 0;
        mul_b_reg <= 0;
    end
end
always@(*)begin
    for(i=0;i<8;i=i+1)begin
        if(mul_b_reg[i]==1'b1)begin
            temp[i] = mul_a_reg << i;
        end
        else begin
            temp[i] = 0;
        end
    end
end
always@(posedge clk)begin
    sum[0] <= temp[0]+temp[1];
    sum[1] <= temp[2]+temp[3];
    sum[2] <= temp[4]+temp[5];
    sum[3] <= temp[6]+temp[7];
end
always@(posedge clk)begin
    mul_out_reg <= sum[0]+sum[1]+sum[2]+sum[3];
end
assign mul_out = (mul_en_out_reg[2])?mul_out_reg:0;
endmodule

module adder_bcd (
    input  [3:0] A,
    input  [3:0] B,
    input  Cin,
    output [3:0] Sum,
    output Cout
);

wire [4:0] temp_sum;
wire [4:0] corrected_sum;
wire correction_needed;

assign temp_sum = A + B + Cin;

assign correction_needed = (temp_sum > 9);

assign corrected_sum = correction_needed ? (temp_sum + 6) : temp_sum;

assign Sum = corrected_sum[3:0];
assign Cout = corrected_sum[4];
endmodule

module multi_pipe_4bit #(
    parameter size = 4,
    parameter N = 2 * size
) (
    input 						clk,
    input 						rst_n,
    input	[size-1:0]			mul_a,
    input	[size-1:0]			mul_b,
    output	reg	[size*2-1:0]	mul_out
);

    wire [7:0] ext_mul_a;
    wire [7:0] ext_mul_b;
    assign ext_mul_a = {{4{1'b0}}, mul_a};
    assign ext_mul_b = {{4{1'b0}}, mul_b};

    genvar i;
    wire [7:0] pp [3:0];
    generate
        for(i = 0; i < 4; i=i+1) begin
            assign pp[i] = (ext_mul_b[i])? ext_mul_a << i : 'd0;
        end
    endgenerate

    reg [7:0] sum_tmp1;
    reg [7:0] sum_tmp2;
    reg [7:0] mul_out_reg;

    always @(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            sum_tmp1 <= 8'd0;
            sum_tmp2 <= 8'd0;
        end
        else begin
            sum_tmp1 <= pp[0] + pp[1];
            sum_tmp2 <= pp[2] + pp[3];
        end
    end

    always @(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            mul_out_reg <= 8'd0;
        end
        else begin
            mul_out_reg <= sum_tmp1 + sum_tmp2;
        end
    end

    assign mul_out = mul_out_reg;
endmodule

module verified_multi_pipe#(
	parameter size = 4
)(
	input 						clk 		,   
	input 						rst_n		,
	input	[size-1:0]			mul_a		,
	input	[size-1:0]			mul_b		,

 	output	reg	[size*2-1:0]	mul_out		
);

parameter N = 2 * size;

reg     [N-1:0]     sum_tmp1                ;
reg     [N-1:0]     sum_tmp2                ;
wire    [N-1:0]     mul_a_extend            ;
wire    [N-1:0]     mul_b_extend            ;

wire    [N-1:0]     mul_result[size-1:0]    ;

genvar i;
generate
    for(i = 0; i < size; i = i + 1) begin:add
        assign mul_result[i] = mul_b[i] ? mul_a_extend << i : 'd0;
    end
endgenerate

assign mul_a_extend = {{size{1'b0}}, mul_a};
assign mul_b_extend = {{size{1'b0}}, mul_b};

always @(posedge clk or negedge rst_n) begin
    if(!rst_n) begin
        sum_tmp1 <= 'd0;
        sum_tmp2 <= 'd0;
    end
    else begin
        sum_tmp1 <= mul_result[0] + mul_result[1];
        sum_tmp2 <= mul_result[2] + mul_result[3];
    end
end

always @(posedge clk or negedge rst_n) begin
    if(!rst_n) begin
        mul_out <= 'd0;
    end
    else begin
        mul_out <= sum_tmp1 + sum_tmp2;
    end
end

endmodule

