module alu #(
    parameter ADD = 6'b100000,
    parameter ADDU = 6'b100001,
    parameter SUB = 6'b100010,
    parameter SUBU = 6'b100011,
    parameter AND = 6'b100100,
    parameter OR = 6'b100101,
    parameter XOR = 6'b100110,
    parameter NOR = 6'b100111,
    parameter SLT = 6'b101010,
    parameter SLTU = 6'b101011,
    parameter SLL = 6'b000000,
    parameter SRL = 6'b000010,
    parameter SRA = 6'b000011,
    parameter SLLV = 6'b000100,
    parameter SRLV = 6'b000110,
    parameter SRAV = 6'b000111,
    parameter JR = 6'b001000,
    parameter LUI = 6'b001111
) (
    input [31:0] a,
    input [31:0] b,
    input [5:0] aluc,
    output [31:0] r,
    output zero,
    output carry,
    output negative,
    output overflow,
    output flag
);

    reg [31:0] res;
    wire [31:0] a_signed, b_signed;

    assign a_signed = {{32{a[31]}}, a};
    assign b_signed = {{32{b[31]}}, b};

    always @(*) begin
        case (aluc)
            ADD: res = a + b;
            ADDU: res = a + b;
            SUB: res = a - b;
            SUBU: res = a - b;
            AND: res = a & b;
            OR: res = a | b;
            XOR: res = a ^ b;
            NOR: res = ~(a | b);
            SLT: res = {32{a_signed < b_signed}};
            SLTU: res = {32{a < b}};
            SLL: res = a << 4;
            SRL: res = a >> 4;
            SRA: res = $signed(a) >>> 4;
            SLLV: res = a << b[4:0];
            SRLV: res = a >> b[4:0];
            SRAV: res = $signed(a) >>> b[4:0];
            LUI: res = {16'h0, a};
            default: res = 32'b0;
        endcase
    end

    assign r = res;
    assign zero = ~|res;
    assign carry = (aluc == ADD || aluc == ADDU) && res[31];
    assign negative = res[31];
    assign overflow = (aluc == ADD || aluc == SUB) && (res[31] != res[30]);
    assign flag = (aluc == SLT || aluc == SLTU) ? 1'b1 : 1'bz;

endmodule

